    /**
    * @return {void}
    */
    XontVenturaBatchEntryComponent.prototype.confirmDuplicateBatchPopup_No = /**
    * @return {void}
    */
    function () {
    this.duplicateGeneratedBatchNoError = "Batch/Serial Number already exists";
    };
    /**
     * @return {void}
     */
    XontVenturaBatchEntryComponent.prototype.validateAddClick = function () {
        var _this = this; // to handle 'this' inside callbacks
        this.busy = this.batchEntryService.HandleExistingBatchNo(this.taskCode, this.territoryCode,
            this.warehouseCode, this.locationCode, this.txtProductCode,
            this.batchForm.txtFirstBatch.trim(), this.batchForm.txtUnitCost)
            .subscribe(
                function (result) {
                    if (result.BatchNumberChangeForCostFlag.trim() === "1") {
                        if (result.Status === "InvalidBatchNo") {
                            _this.mainErrorMsg = result.Message;
                        }
                        else if (result.Status === "GenerateBatchNo") {
                            // Check for Existing and increment
                            if (result.BatchNumber.includes('_')) {
                                var parts = result.BatchNumber.split('_');
                                var prefix = parts[0];
                                var existingBatch = _this.selectedBatchSerials.find(function (batch) {
                                    return batch.BatchSerial.startsWith(prefix + '_');
                                });
    
                                if (existingBatch) {
                                    var existingParts = existingBatch.BatchSerial.split('_');
                                    var existingSuffix = existingParts[1];
                                    var suffixNumber = parseInt(existingSuffix);
                                    if (!isNaN(suffixNumber)) {
                                        var incrementedSuffix = suffixNumber + 1;
                                        _this.duplicateGeneratedBatchNo = prefix + "_" + incrementedSuffix;
                                    } else {
                                        // Handle case where suffix is not a number
                                        _this.duplicateGeneratedBatchNo = result.BatchNumber + "_1"; // Default behavior to add _1 if suffix isn't numeric
                                    }
                                } else {
                                    // If no existing batch starts with the same prefix, use the current batchNumber
                                    _this.duplicateGeneratedBatchNo = result.BatchNumber;
                                }
                            } else {
                                // If there's no underscore in the original batchNumber, perhaps handle differently or leave as is
                                _this.duplicateGeneratedBatchNo = result.BatchNumber;
                            }
    
                            _this.duplicateBatchPrompt.showConfirm(result.Message, "Yes", "No");
                            _this.mainErrorMsg = _this.duplicateGeneratedBatchNoError;
                        }
                        else {
                            _this.batchForm.txtFirstBatch = result.BatchNumber;
                            _this.add();
                        }
                    } else {
                        _this.add();
                    }
                },
                function (err) {
                    console.log(err);
                });
    };

