var BatchFilterPipe = (function () {
    function BatchFilterPipe() {
    }
    /**
     * @param {?} items
     * @param {?} query
     * @return {?}
     */
    BatchFilterPipe.prototype.transform = /**
     * @param {?} items
     * @param {?} query
     * @return {?}
     */
    function (items, query) {
        if (!items) {
            return [];
        }
        if (!query) {
            return items;
        }
        //console.log(items, query);
        var /** @type {?} */ filteredList = [];
        var /** @type {?} */ selectedList = [];
        if (query.trim() != '') {
            for (var /** @type {?} */ i = 0; i < items.length; i++) {
                if (items[i].YesNo == true) {
                    selectedList.push(items[i]);
                }
                else {
                    if ((items[i].BatchSerialNumber.toUpperCase().trim()).startsWith(query.toUpperCase().trim()) == true) {
                        filteredList.push(items[i]);
                    }
                }
            }
            filteredList = filteredList.concat(selectedList);
            return filteredList;
        }
        return items;
    };
    BatchFilterPipe.decorators = [
        { type: Pipe, args: [{
                    name: 'batchFilter'
                },] },
    ];
    return BatchFilterPipe;
}());

